# scraper module for ai‑daily‑brief\n\nimport requests\nimport feedparser\nfrom typing import List, Dict\n\nARXIV_API_URL = "http://export.arxiv.org/api/query"\n\ndef get_latest_papers(category: str = "cs.AI", max_results: int = 10) -> List[Dict[str, str]]:\n    """Fetch the latest arXiv papers for a given category using the arXiv API.\n    Returns a list of dicts with keys: id, title, summary, link, authors.\n    """\n    params = {\n        "search_query": f"cat:{category}",\n        "start": 0,\n        "max_results": max_results,\n        "sortBy": "lastUpdatedDate",\n        "sortOrder": "descending",\n    }\n    response = requests.get(ARXIV_API_URL, params=params, timeout=10)\n    response.raise_for_status()\n    feed = feedparser.parse(response.text)\n    papers = []\n    for entry in feed.entries:\n        paper = {\n            "id": entry.id,\n            "title": entry.title.strip().replace('\n', ' '),\n            "summary": entry.summary.strip().replace('\n', ' '),\n            "link": entry.link,\n            "authors": ", ".join(author.name for author in entry.authors),\n        }\n        papers.append(paper)\n    return papers\n\nif __name__ == "__main__":\n    for p in get_latest_papers():\n        print(p["title"])\n